import { Component, inject, OnInit } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { AdminCasesService } from '../../../application/services/admin-cases.service';
import { CaseDetail } from '../../../application/models/backoffice.models';

@Component({
  selector: 'bo-case-detail',
  templateUrl: './case-detail.component.html',
  styleUrls: ['./case-detail.component.css']
})
export class CaseDetailComponent implements OnInit {
  private readonly adminCasesService = inject(AdminCasesService);
  private readonly route = inject(ActivatedRoute);
  private readonly router = inject(Router);

  caseDetail: CaseDetail | null = null;
  isLoading = true;
  activeTab: 'timeline' | 'documents' | 'data' | 'actions' = 'timeline';
  showStatusModal = false;
  newStatus = '';
  tabs: ('timeline' | 'documents' | 'data' | 'actions')[] = ['timeline', 'documents', 'data', 'actions'];

  statusOptions = [
    { value: 'IN_PROGRESS', label: 'En Tramitacion' },
    { value: 'PENDING_AMENDMENT', label: 'Pendiente Subsanacion' },
    { value: 'RESOLVED', label: 'Resuelto' },
    { value: 'REJECTED', label: 'Rechazado' }
  ];

  ngOnInit(): void {
    const id = this.route.snapshot.paramMap.get('id');
    if (id) {
      this.loadCase(id);
    }
  }

  loadCase(id: string): void {
    this.isLoading = true;
    this.adminCasesService.getDetail(id).subscribe({
      next: (detail) => {
        this.caseDetail = detail;
        this.isLoading = false;
      },
      error: () => {
        this.isLoading = false;
      }
    });
  }

  openStatusModal(): void {
    this.newStatus = this.caseDetail?.status || '';
    this.showStatusModal = true;
  }

  closeStatusModal(): void {
    this.showStatusModal = false;
  }

  updateStatus(): void {
    if (!this.caseDetail || !this.newStatus) return;

    this.adminCasesService.updateStatus(this.caseDetail.id, this.newStatus).subscribe({
      next: () => {
        this.loadCase(this.caseDetail!.id);
        this.showStatusModal = false;
      },
      error: () => {
        // Error handled by interceptor
      }
    });
  }

  getStatusLabel(status: string): string {
    const option = this.statusOptions.find(o => o.value === status);
    return option?.label || status;
  }

  getStatusClass(status: string): string {
    const classes: Record<string, string> = {
      DRAFT: 'bg-gray-100 text-gray-800',
      SUBMITTED: 'bg-blue-100 text-blue-800',
      IN_PROGRESS: 'bg-yellow-100 text-yellow-800',
      PENDING_AMENDMENT: 'bg-orange-100 text-orange-800',
      RESOLVED: 'bg-green-100 text-green-800',
      REJECTED: 'bg-red-100 text-red-800'
    };
    return classes[status] || 'bg-gray-100 text-gray-800';
  }

  formatFileSize(bytes: number): string {
    if (bytes < 1024) return bytes + ' B';
    if (bytes < 1048576) return (bytes / 1024).toFixed(1) + ' KB';
    return (bytes / 1048576).toFixed(1) + ' MB';
  }

  getTabLabel(tab: string): string {
    const labels: Record<string, string> = {
      timeline: 'Historial',
      documents: 'Documentos',
      data: 'Datos',
      actions: 'Acciones'
    };
    return labels[tab] || tab;
  }
}
<div *ngIf="isLoading" class="flex items-center justify-center h-64">
  <div class="text-gray-500">Cargando expediente...</div>
</div>

<div *ngIf="!isLoading && caseDetail">
  <!-- Header -->
  <div class="bg-white rounded-lg shadow p-6 mb-6">
    <div class="flex items-start justify-between mb-4">
      <div>
        <h2 class="text-xl font-bold text-gray-900">{{ caseDetail.title }}</h2>
        <p class="text-sm text-gray-500 mt-1">ID: {{ caseDetail.id }}</p>
      </div>
      <div class="flex items-center gap-3">
        <span class="px-3 py-1 text-sm font-medium rounded-full" [ngClass]="getStatusClass(caseDetail.status)">
          {{ getStatusLabel(caseDetail.status) }}
        </span>
        <button
          (click)="openStatusModal()"
          class="px-4 py-2 bg-blue-600 text-white text-sm font-medium rounded-md hover:bg-blue-700 transition-colors"
        >
          Cambiar Estado
        </button>
      </div>
    </div>

    <div class="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm">
      <div>
        <span class="text-gray-500">Tipo:</span>
        <span class="ml-2 font-medium">{{ caseDetail.procedureType }}</span>
      </div>
      <div>
        <span class="text-gray-500">Ciudadano:</span>
        <span class="ml-2 font-medium">{{ caseDetail.citizenName }}</span>
      </div>
      <div>
        <span class="text-gray-500">Unidad:</span>
        <span class="ml-2 font-medium">{{ caseDetail.assignedUnit || '-' }}</span>
      </div>
      <div>
        <span class="text-gray-500">Tarea Actual:</span>
        <span class="ml-2 font-medium">{{ caseDetail.currentTask || '-' }}</span>
      </div>
    </div>
  </div>

  <!-- Tabs -->
  <div class="bg-white rounded-lg shadow">
    <div class="border-b border-gray-200">
      <nav class="flex -mb-px">
        <button
          *ngFor="let tab of tabs"
          (click)="activeTab = tab"
          class="px-6 py-4 text-sm font-medium border-b-2 transition-colors"
          [class.border-blue-500]="activeTab === tab"
          [class.text-blue-600]="activeTab === tab"
          [class.border-transparent]="activeTab !== tab"
          [class.text-gray-500]="activeTab !== tab"
        >
          {{ getTabLabel(tab) }}
        </button>
      </nav>
    </div>

    <!-- Timeline tab -->
    <div *ngIf="activeTab === 'timeline'" class="p-6">
      <ul class="space-y-4">
        <li *ngFor="let event of caseDetail.timeline" class="flex gap-4">
          <div class="flex-shrink-0 w-2 h-2 bg-blue-600 rounded-full mt-2"></div>
          <div>
            <div class="font-medium text-gray-900">{{ event.title }}</div>
            <div class="text-sm text-gray-500">{{ event.description }}</div>
            <div class="text-xs text-gray-400 mt-1">
              {{ event.date | date: 'dd/MM/yyyy HH:mm' }} - {{ event.actor }}
            </div>
          </div>
        </li>
        <li *ngIf="caseDetail.timeline.length === 0" class="text-gray-500 text-sm">
          No hay eventos en el historial
        </li>
      </ul>
    </div>

    <!-- Documents tab -->
    <div *ngIf="activeTab === 'documents'" class="p-6">
      <table class="w-full">
        <thead class="bg-gray-50">
          <tr>
            <th class="px-4 py-2 text-left text-xs font-medium text-gray-500 uppercase">Nombre</th>
            <th class="px-4 py-2 text-left text-xs font-medium text-gray-500 uppercase">Tipo</th>
            <th class="px-4 py-2 text-left text-xs font-medium text-gray-500 uppercase">Tamano</th>
            <th class="px-4 py-2 text-left text-xs font-medium text-gray-500 uppercase">Subido por</th>
            <th class="px-4 py-2 text-left text-xs font-medium text-gray-500 uppercase">Fecha</th>
          </tr>
        </thead>
        <tbody class="divide-y divide-gray-200">
          <tr *ngFor="let doc of caseDetail.attachments">
            <td class="px-4 py-3 text-sm font-medium text-gray-900">{{ doc.name }}</td>
            <td class="px-4 py-3 text-sm text-gray-500">{{ doc.type }}</td>
            <td class="px-4 py-3 text-sm text-gray-500">{{ formatFileSize(doc.size) }}</td>
            <td class="px-4 py-3 text-sm text-gray-500">{{ doc.uploadedBy }}</td>
            <td class="px-4 py-3 text-sm text-gray-500">{{ doc.uploadedAt | date: 'dd/MM/yyyy' }}</td>
          </tr>
          <tr *ngIf="caseDetail.attachments.length === 0">
            <td colspan="5" class="px-4 py-6 text-center text-gray-500 text-sm">
              No hay documentos adjuntos
            </td>
          </tr>
        </tbody>
      </table>
    </div>

    <!-- Data tab -->
    <div *ngIf="activeTab === 'data'" class="p-6">
      <pre class="bg-gray-50 p-4 rounded text-sm overflow-auto max-h-96">{{ caseDetail.formData | json }}</pre>
    </div>

    <!-- Actions tab -->
    <div *ngIf="activeTab === 'actions'" class="p-6">
      <div class="space-y-4">
        <div>
          <h4 class="font-medium text-gray-900 mb-2">Acciones Disponibles</h4>
          <p class="text-sm text-gray-500">
            Tarea actual: <strong>{{ caseDetail.currentTask || 'Ninguna' }}</strong>
          </p>
        </div>
        <div class="flex gap-3">
          <button
            [routerLink]="['/cases', caseDetail.id, 'task', caseDetail.currentTask]"
            [disabled]="!caseDetail.currentTask"
            class="px-4 py-2 bg-blue-600 text-white text-sm font-medium rounded-md hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
          >
            Resolver Tarea
          </button>
          <button
            (click)="openStatusModal()"
            class="px-4 py-2 border border-gray-300 text-gray-700 text-sm font-medium rounded-md hover:bg-gray-50 transition-colors"
          >
            Cambiar Estado
          </button>
        </div>
      </div>
    </div>
  </div>
</div>

<!-- Status modal -->
<div *ngIf="showStatusModal" class="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
  <div class="bg-white rounded-lg shadow-lg p-6 w-full max-w-md">
    <h3 class="text-lg font-semibold text-gray-900 mb-4">Cambiar Estado del Expediente</h3>
    <select
      [(ngModel)]="newStatus"
      class="w-full border border-gray-300 rounded-md px-3 py-2 mb-4 focus:outline-none focus:ring-2 focus:ring-blue-500"
    >
      <option *ngFor="let opt of statusOptions" [value]="opt.value">{{ opt.label }}</option>
    </select>
    <div class="flex justify-end gap-3">
      <button
        (click)="closeStatusModal()"
        class="px-4 py-2 border border-gray-300 text-gray-700 text-sm font-medium rounded-md hover:bg-gray-50"
      >
        Cancelar
      </button>
      <button
        (click)="updateStatus()"
        class="px-4 py-2 bg-blue-600 text-white text-sm font-medium rounded-md hover:bg-blue-700"
      >
        Confirmar
      </button>
    </div>
  </div>
</div>
